## h1 <- h1 coupling contributions
from . import logger, tools, ascontiguousarray

# CCAA <- CCEA
def compute_sigma_vector__H1__h1_h1__CCAA_CCEA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccaa = mr_adc.h1.ccaa

    ## Molecular Orbitals Energies
    e_extern = mr_adc.mo_energy.e
    
    ## One-electron integrals
    h_aa = mr_adc.h1eff.aa
    h_ae = mr_adc.h1eff.ae

    ## Two-electron integrals
    v_xxae = mr_adc.v2e.xxae
    v_xaex = mr_adc.v2e.xaex
    v_aaaa = mr_adc.v2e.aaaa
    v_aaae = mr_adc.v2e.aaae

    ## Amplitudes
    t1_ae = mr_adc.t1.ae
    t1_aaae = mr_adc.t1.aaae

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa
    rdm_cccaaa = mr_adc.rdm.cccaaa

    sigma_KLWU  = einsum('KLaU,Wa->KLWU', X, h_ae, optimize = einsum_type)
    sigma_KLWU += einsum('LKaW,Ua->KLWU', X, h_ae, optimize = einsum_type)
    sigma_KLWU += einsum('KLax,UxWa->KLWU', X, v_aaae, optimize = einsum_type)
    sigma_KLWU -= einsum('KiaU,iLWa->KLWU', X, v_xxae, optimize = einsum_type)
    sigma_KLWU -= einsum('KiaW,LUai->KLWU', X, v_xaex, optimize = einsum_type)
    sigma_KLWU += einsum('LKax,WxUa->KLWU', X, v_aaae, optimize = einsum_type)
    sigma_KLWU -= einsum('LiaU,KWai->KLWU', X, v_xaex, optimize = einsum_type)
    sigma_KLWU -= einsum('LiaW,iKUa->KLWU', X, v_xxae, optimize = einsum_type)
    sigma_KLWU += 2 * einsum('iKaW,LUai->KLWU', X, v_xaex, optimize = einsum_type)
    sigma_KLWU -= einsum('iKaW,iLUa->KLWU', X, v_xxae, optimize = einsum_type)
    sigma_KLWU += 2 * einsum('iLaU,KWai->KLWU', X, v_xaex, optimize = einsum_type)
    sigma_KLWU -= einsum('iLaU,iKWa->KLWU', X, v_xxae, optimize = einsum_type)
    sigma_KLWU += einsum('KLaU,a,Wa->KLWU', X, e_extern, t1_ae, optimize = einsum_type)
    sigma_KLWU += einsum('KLax,a,UWxa->KLWU', X, e_extern, t1_aaae, optimize = einsum_type)
    sigma_KLWU += einsum('LKaW,a,Ua->KLWU', X, e_extern, t1_ae, optimize = einsum_type)
    sigma_KLWU += einsum('LKax,a,WUxa->KLWU', X, e_extern, t1_aaae, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KLax,Wa,Ux->KLWU', X, h_ae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('LKax,Ua,Wx->KLWU', X, h_ae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= einsum('KLaU,Wx,xa->KLWU', X, h_aa, t1_ae, optimize = einsum_type)
    sigma_KLWU -= einsum('KLax,Uy,yWxa->KLWU', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLWU -= einsum('KLax,Wy,Uyxa->KLWU', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLWU += einsum('KLax,xy,UWya->KLWU', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLWU -= einsum('LKaW,Ux,xa->KLWU', X, h_aa, t1_ae, optimize = einsum_type)
    sigma_KLWU -= einsum('LKax,Uy,Wyxa->KLWU', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLWU -= einsum('LKax,Wy,yUxa->KLWU', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLWU += einsum('LKax,xy,WUya->KLWU', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLWU -= einsum('KLax,ya,UxWy->KLWU', X, t1_ae, v_aaaa, optimize = einsum_type)
    sigma_KLWU -= einsum('KLax,yzxa,UyWz->KLWU', X, t1_aaae, v_aaaa, optimize = einsum_type)
    sigma_KLWU -= einsum('LKax,ya,UyWx->KLWU', X, t1_ae, v_aaaa, optimize = einsum_type)
    sigma_KLWU -= einsum('LKax,yzxa,UzWy->KLWU', X, t1_aaae, v_aaaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KLaU,Wxya,yx->KLWU', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += einsum('KLaU,xyWa,xy->KLWU', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KLax,Uxya,Wy->KLWU', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KLax,UyWa,xy->KLWU', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('KLax,Uyza,Wyxz->KLWU', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('KLax,Uyza,Wyzx->KLWU', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('KLax,Wyza,Uyxz->KLWU', X, v_aaae, rdm_ccaa, optimize = einsum_type)
