    sigma_KLWU += 1/2 * einsum('LiaU,Kxai,Wx->KLWU', X, v_xaex, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiaW,iKxa,Ux->KLWU', X, v_xxae, rdm_ca, optimize = einsum_type)
