def compute_sigma_vector__H1__h1_h1__CCEE_CCEA__V_AEEE(mr_adc, X, sigma, v_aeee):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccee = mr_adc.h1.ccee

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca

    sigma_KLCD  = einsum('KLax,xDaC->KLCD', X, v_aeee, optimize = einsum_type)
    sigma_KLCD += einsum('LKax,xCaD->KLCD', X, v_aeee, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLax,yDaC,xy->KLCD', X, v_aeee, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('LKax,yCaD,xy->KLCD', X, v_aeee, rdm_ca, optimize = einsum_type)
    sigma[ccee] += ascontiguousarray(sigma_KLCD).reshape(-1)

    mr_adc.log.timer_debug("contracting v2e.aeee", *cput1)

# CAEE <- CCEA
def compute_sigma_vector__H1__h1_h1__CAEE_CCEA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    caee = mr_adc.h1.caee

    ## Two-electron integrals
    v_xaea = mr_adc.v2e.xaea

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KWCD  = einsum('KiCx,ixDy,Wy->KWCD', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD -= 1/2 * einsum('KiCx,iyDx,Wy->KWCD', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD -= 1/2 * einsum('KiCx,iyDz,Wxzy->KWCD', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD -= 1/2 * einsum('iKCx,ixDy,Wy->KWCD', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD += 1/6 * einsum('iKCx,iyDz,Wxyz->KWCD', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD += 1/3 * einsum('iKCx,iyDz,Wxzy->KWCD', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD -= 1/2 * einsum('iKDx,iyCx,Wy->KWCD', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCD += 1/3 * einsum('iKDx,iyCz,Wxyz->KWCD', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCD += 1/6 * einsum('iKDx,iyCz,Wxzy->KWCD', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma[caee] += ascontiguousarray(sigma_KWCD).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CAEE-CCEA", *cput1)

# CAAA <- CCEA
