# CVAA <- CCEA
def compute_sigma_vector__H1__h1_h1__CVAA_CCEA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    cvaa = mr_adc.h1.cvaa

    ## Two-electron integrals
    v_xvae = mr_adc.v2e.xvae
    v_vaex = mr_adc.v2e.vaex

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLWU =- einsum('KiaU,iLWa->KLWU', X, v_xvae, optimize = einsum_type)
    sigma_KLWU -= einsum('KiaW,LUai->KLWU', X, v_vaex, optimize = einsum_type)
    sigma_KLWU += 2 * einsum('iKaW,LUai->KLWU', X, v_vaex, optimize = einsum_type)
    sigma_KLWU -= einsum('iKaW,iLUa->KLWU', X, v_xvae, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiaU,iLxa,Wx->KLWU', X, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiaW,Lxai,Ux->KLWU', X, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kiax,LUai,Wx->KLWU', X, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kiax,Lyai,UWxy->KLWU', X, v_vaex, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kiax,Lyai,UWyx->KLWU', X, v_vaex, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kiax,iLWa,Ux->KLWU', X, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kiax,iLya,UWxy->KLWU', X, v_xvae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kiax,iLya,UWyx->KLWU', X, v_xvae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= einsum('iKaW,Lxai,Ux->KLWU', X, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('iKaW,iLxa,Ux->KLWU', X, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= einsum('iKax,LUai,Wx->KLWU', X, v_vaex, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('iKax,Lyai,UWxy->KLWU', X, v_vaex, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 2/3 * einsum('iKax,Lyai,UWyx->KLWU', X, v_vaex, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('iKax,iLUa,Wx->KLWU', X, v_xvae, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('iKax,iLya,UWxy->KLWU', X, v_xvae, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('iKax,iLya,UWyx->KLWU', X, v_xvae, rdm_ccaa, optimize = einsum_type)
    sigma[cvaa] += ascontiguousarray(sigma_KLWU).reshape(-1) 

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CVAA-CCEA", *cput1)

# CVEA <- CCEA
def compute_sigma_vector__H1__h1_h1__CVEA_CCEA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    cvea__abab = mr_adc.h1.cvea__abab
    cvea__baab = mr_adc.h1.cvea__baab
 
    ## Two-electron integrals
    v_xxvx = mr_adc.v2e.xxvx
    v_xvee = mr_adc.v2e.xvee
    v_vxaa = mr_adc.v2e.vxaa
    v_vaax = mr_adc.v2e.vaax
    v_veex = mr_adc.v2e.veex

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLCW_abab  = 2 * einsum('KiCx,LWxi->KLCW', X, v_vaax, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiCx,LixW->KLCW', X, v_vxaa, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiaW,iLCa->KLCW', X, v_xvee, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('iKCx,LWxi->KLCW', X, v_vaax, optimize = einsum_type)
    sigma_KLCW_abab += einsum('ijCW,KiLj->KLCW', X, v_xxvx, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiCx,LWyi,xy->KLCW', X, v_vaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,Lixy,Wy->KLCW', X, v_vxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,LiyW,xy->KLCW', X, v_vxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,Liyz,Wyxz->KLCW', X, v_vxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= einsum('KiCx,Lyxi,Wy->KLCW', X, v_vaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('KiCx,Lyzi,Wzyx->KLCW', X, v_vaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('Kiax,iLCa,Wx->KLCW', X, v_xvee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('iKCx,LWyi,xy->KLCW', X, v_vaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/2 * einsum('iKCx,Lyxi,Wy->KLCW', X, v_vaax, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/6 * einsum('iKCx,Lyzi,Wzxy->KLCW', X, v_vaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/3 * einsum('iKCx,Lyzi,Wzyx->KLCW', X, v_vaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('ijCx,KiLj,Wx->KLCW', X, v_xxvx, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab -= 1/2 * einsum('KiCx,Liyz,yz,Wx->KLCW', X, v_vxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_abab += 1/4 * einsum('KiCx,Lyzi,zy,Wx->KLCW', X, v_vaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma[cvea__abab] += ascontiguousarray(sigma_KLCW_abab).reshape(-1)

    sigma_KLCW_baab  = einsum('KiaW,LCai->KLCW', X, v_veex, optimize = einsum_type)
    sigma_KLCW_baab += einsum('iKCx,LixW->KLCW', X, v_vxaa, optimize = einsum_type)
    sigma_KLCW_baab -= 2 * einsum('iKaW,LCai->KLCW', X, v_veex, optimize = einsum_type)
    sigma_KLCW_baab += einsum('iKaW,iLCa->KLCW', X, v_xvee, optimize = einsum_type)
    sigma_KLCW_baab -= einsum('ijCW,KjLi->KLCW', X, v_xxvx, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('Kiax,LCai,Wx->KLCW', X, v_veex, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iKCx,Lixy,Wy->KLCW', X, v_vxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iKCx,LiyW,xy->KLCW', X, v_vxaa, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iKCx,Liyz,Wyxz->KLCW', X, v_vxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/3 * einsum('iKCx,Lyzi,Wzxy->KLCW', X, v_vaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += 1/6 * einsum('iKCx,Lyzi,Wzyx->KLCW', X, v_vaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_baab += einsum('iKax,LCai,Wx->KLCW', X, v_veex, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/2 * einsum('iKax,iLCa,Wx->KLCW', X, v_xvee, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('ijCx,KjLi,Wx->KLCW', X, v_xxvx, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab += 1/2 * einsum('iKCx,Liyz,yz,Wx->KLCW', X, v_vxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLCW_baab -= 1/4 * einsum('iKCx,Lyzi,zy,Wx->KLCW', X, v_vaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma[cvea__baab] += ascontiguousarray(sigma_KLCW_baab).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CVEA-CCEA", *cput1)

# CVEE <- CCEA
def compute_sigma_vector__H1__h1_h1__CVEE_CCEA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    cvee = mr_adc.h1.cvee

    ## Two-electron integrals
    v_xaev = mr_adc.v2e.xaev
    v_vxae = mr_adc.v2e.vxae

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca

    sigma_KLCD =- einsum('KiCx,LixD->KLCD', X, v_vxae, optimize = einsum_type)
    sigma_KLCD += 2 * einsum('KiCx,ixDL->KLCD', X, v_xaev, optimize = einsum_type)
    sigma_KLCD -= einsum('iKCx,ixDL->KLCD', X, v_xaev, optimize = einsum_type)
    sigma_KLCD -= einsum('iKDx,LixC->KLCD', X, v_vxae, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KiCx,LiyD,xy->KLCD', X, v_vxae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KiCx,iyDL,xy->KLCD', X, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('iKCx,iyDL,xy->KLCD', X, v_xaev, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('iKDx,LiyC,xy->KLCD', X, v_vxae, rdm_ca, optimize = einsum_type)
    sigma[cvee] += ascontiguousarray(sigma_KLCD).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CVEE-CCEA", *cput1)

